def unit_of_work(metadata=None, timeout=None):
    def decorator(f):
        def wrapper(*args, **kwargs):
            # Validate timeout
            if timeout is not None:
                if not isinstance(timeout, (int, float)):
                    raise TypeError("Timeout must be a number")
                if timeout < 0:
                    raise ValueError("Timeout cannot be negative")

            # Validate metadata
            if metadata is not None:
                if not isinstance(metadata, dict):
                    raise TypeError("Metadata must be a dictionary")

            # Store original function attributes
            wrapper.__name__ = f.__name__
            wrapper.__doc__ = f.__doc__

            # Add transaction metadata
            def wrapped_tx(tx, *args, **kwargs):
                if metadata:
                    tx.set_metadata(metadata)
                if timeout is not None:
                    tx.set_timeout(timeout)
                return f(tx, *args, **kwargs)

            return wrapped_tx(*args, **kwargs)

        return wrapper
    return decorator

def values(self, *keys):
    """
    Devuelve los valores del registro, filtrando opcionalmente para incluir solo ciertos valores por índice o clave.

    :param keys: índices o claves de los elementos a incluir; si no se proporcionan, se incluirán todos los valores  
    :return: lista de valores  
    :rtype: list
    """
    if not keys:
        # Si no se proporcionan keys, devolver todos los valores
        return list(self._data.values())

    result = []
    for key in keys:
        if isinstance(key, int):
            # Si es un índice numérico
            if 0 <= key < len(self._data):
                # Obtener el valor en la posición key
                result.append(list(self._data.values())[key])
        else:
            # Si es una clave
            if key in self._data:
                result.append(self._data[key])

    return result

def data(self, *keys):
    # Si no se proporcionan claves, devolver todos los datos
    if not keys:
        return dict(zip(self._fields, self))

    # Crear diccionario con las claves solicitadas
    result = {}

    for key in keys:
        # Si la clave es un índice numérico
        if isinstance(key, int):
            # Verificar que el índice esté dentro de los límites
            if key < 0 or key >= len(self):
                raise IndexError(f"Index {key} out of range")
            result[self._fields[key]] = self[key]

        # Si la clave es un string
        else:
            # Si la clave existe en los campos, obtener su valor
            if key in self._fields:
                idx = self._fields.index(key)
                result[key] = self[idx]
            # Si no existe, asignar None
            else:
                result[key] = None

    return result

def pop_u16(self):
    if len(self.data) < 2:
        raise ValueError("Not enough bytes to pop u16")
    value = int.from_bytes(self.data[-2:], byteorder='big', signed=False)
    self.data = self.data[:-2]
    return value

def begin(self, mode=None, bookmarks=None, metadata=None, timeout=None,
          db=None, imp_user=None, dehydration_hooks=None,
          hydration_hooks=None, **handlers):

    # Validar el modo
    valid_modes = ("READ", "WRITE")
    if mode is not None and mode not in valid_modes:
        raise ValueError(f"Mode must be one of {valid_modes}")

    # Construir los extras para el mensaje BEGIN
    extras = {}

    if mode is not None:
        extras["mode"] = mode

    if bookmarks:
        extras["bookmarks"] = list(bookmarks)

    if metadata:
        extras["metadata"] = metadata

    if timeout is not None:
        extras["timeout"] = timeout

    if db is not None:
        extras["db"] = db

    if imp_user is not None:
        extras["imp_user"] = imp_user

    # Configurar los hooks de serialización si se proporcionan
    if dehydration_hooks:
        self.dehydration_hooks.update(dehydration_hooks)

    if hydration_hooks:
        self.hydration_hooks.update(hydration_hooks)

    # Crear y enviar el mensaje BEGIN
    message = ("BEGIN", extras)

    # Crear objeto Response con los handlers proporcionados
    response = Response(self, message, **handlers)

    # Agregar el mensaje a la cola de salida
    self.append(message, response)

    return response

def point_type(name, fields, srid_map):
    """
    Crear dinámicamente una subclase de 'Point'.
    """
    class DynamicPoint(Point):
        def __init__(self, *args, **kwargs):
            super().__init__(*args, **kwargs)
            for field in fields:
                setattr(self, field, None)

        def __str__(self):
            field_str = ', '.join(f'{field}={getattr(self, field)}' for field in fields)
            return f"{name}({field_str}, srid={self.srid})"

        @property
        def srid(self):
            return srid_map.get(self.__class__.__name__, 4326)

    DynamicPoint.__name__ = name
    return DynamicPoint

def deprecated(message):
    def decorator(func):
        def wrapper(*args, **kwargs):
            import warnings
            warnings.warn(
                f"{func.__name__}: {message}",
                category=DeprecationWarning,
                stacklevel=2
            )
            return func(*args, **kwargs)
        wrapper.__name__ = func.__name__
        wrapper.__doc__ = func.__doc__
        return wrapper
    return decorator

