def normalize_cmd(cmd: tuple[str, ...]) -> tuple[str, ...]:
    """
    Correcciones para los siguientes problemas en Windows:  
    - https://bugs.python.org/issue8557  
    - Windows no interpreta correctamente los 'shebangs'  

    Esta función también permite que los 'shebangs' con rutas profundas funcionen correctamente.
    """
    if not cmd:
        return cmd

    # Si el primer elemento es un archivo Python, no necesita normalización
    if cmd[0].endswith('.py'):
        return cmd

    # Lee el primer archivo para buscar shebang
    try:
        with open(cmd[0], 'rb') as f:
            first_line = f.readline().decode('utf-8').strip()

        # Si tiene shebang
        if first_line.startswith('#!'):
            interpreter = first_line[2:].strip().split()

            # Si el shebang especifica python, usar python del sistema
            if 'python' in interpreter[-1].lower():
                return ('python', *cmd)

            # Para otros shebangs, usar el intérprete especificado
            return (*interpreter, *cmd)

    except (IOError, UnicodeDecodeError):
        pass

    return cmd

def cached(cache, key=hashkey, lock=None):
    """
    Decorador para envolver una función con una llamada que memoriza y guarda  
    los resultados en una caché.
    """
    def decorator(func):
        def wrapper(*args, **kwargs):
            k = key(*args, **kwargs)

            try:
                return cache[k]
            except KeyError:
                pass

            if lock is not None:
                with lock:
                    if k in cache:
                        return cache[k]
                    result = func(*args, **kwargs)
                    cache[k] = result
            else:
                result = func(*args, **kwargs)
                cache[k] = result

            return result

        return wrapper
    return decorator

def setdefault(self, key, default=None):
    """
    `D.setdefault(k[, d]) -> D.get(k, d)`, también establece `D[k] = d` si `k` no está en `D`.
    """
    try:
        return self[key]
    except KeyError:
        self[key] = default
        return default

def get(self, key, default=None):
    """
    D.get(k[, d]) -> D[k] si k está en D, de lo contrario d. d tiene como valor predeterminado 'None'.
    """
    try:
        return self[key]
    except KeyError:
        return default

def cachedmethod(cache, key=hashkey, lock=None):
    """
    Decorador para envolver un método de clase o de instancia con una función memoizadora
    que guarda los resultados en una caché.
    """
    def decorator(method):
        def wrapper(self, *args, **kwargs):
            # Obtener la caché específica de la instancia/clase
            cache_attr = cache(self)

            if cache_attr is None:  # Si no hay caché, ejecutar método sin cachear
                return method(self, *args, **kwargs)

            # Generar clave única para los argumentos
            k = key(args, kwargs)

            try:
                # Intentar obtener resultado de caché
                if lock is not None:
                    with lock:
                        return cache_attr[k]
                else:
                    return cache_attr[k]

            except KeyError:
                # Si no está en caché, calcular y guardar
                result = method(self, *args, **kwargs)

                if lock is not None:
                    with lock:
                        cache_attr[k] = result
                else:
                    cache_attr[k] = result

                return result

        return wrapper

    return decorator

