def reset(self):
    """
    Restablece el histograma.

    El contexto actual se restablece a un diccionario vacío.
    Los contenedores (bins) se reinicializan con el *initial_value*
    o con *make_bins()* (dependiendo de la inicialización).
    """
    self.context = {}

    if hasattr(self, 'initial_value'):
        self.bins = {key: self.initial_value for key in self.bins.keys()}
    else:
        self.bins = self.make_bins()

def to_csv(self, separator=",", header=None):
    result = []

    # Add header if provided
    if header is not None:
        result.append(str(header))

    # Convert each point to CSV format
    for point in self:
        # Convert coordinates to string, separated by separator
        coord_str = separator.join(str(x) for x in point.coords)

        # Convert values to string, separated by separator 
        if hasattr(point, 'values'):
            values_str = separator.join(str(x) for x in point.values)
            # Combine coordinates and values
            point_str = separator.join([coord_str, values_str])
        else:
            point_str = coord_str

        result.append(point_str)

    # Join all lines with newlines
    return "\n".join(result)

def _get_err_indices(self, coord_name):
    """
    Obtener los índices de error correspondientes a una coordenada.
    """
    if coord_name == 'x':
        return [0, 3, 4]
    elif coord_name == 'y': 
        return [1, 3, 5]
    elif coord_name == 'z':
        return [2, 4, 5]
    else:
        raise ValueError(f"Invalid coordinate name: {coord_name}")

def _update_context(self, context):
    # Inicializar diccionario de errores si no existe
    if not hasattr(context, 'error'):
        context.error = {}

    # Mapeo de nombres de campos a coordenadas x,y,z
    coord_map = {'E': 'x', 'n': 'y', 't': 'z'}

    # Buscar campos de error en el grafo
    for field in self.fields:
        # Buscar campos que terminan en _low o _high
        if field.endswith('_low') or field.endswith('_high'):
            # Obtener el nombre base del campo (sin _low/_high)
            base = field.rsplit('_', 1)[0]
            # Obtener el tipo de límite (low/high)
            limit = field.rsplit('_', 1)[1]

            # Si el campo base está en el mapeo de coordenadas
            if base in coord_map:
                coord = coord_map[base]
                # Crear entrada en el diccionario de errores
                error_key = f"{coord}_{limit}"
                if error_key not in context.error:
                    context.error[error_key] = {}
                # Guardar el índice del campo de error
                context.error[error_key]['index'] = self.fields.index(field)

def is_fill_request_seq(seq):
    from typing import Sequence
    from fillrequest import FillRequest
    from source import Source

    # Check if seq is a FillRequest directly
    if isinstance(seq, FillRequest):
        return True

    # Check if seq is a Source sequence
    if isinstance(seq, Source):
        return False

    # Check if seq is a sequence
    if not isinstance(seq, Sequence):
        return False

    # Check if sequence contains at least one FillRequest
    for item in seq:
        if isinstance(item, FillRequest):
            return True

    return False

def is_fill_request_el(obj):
    return hasattr(obj, 'fill') and callable(getattr(obj, 'fill')) and \
           hasattr(obj, 'request') and callable(getattr(obj, 'request'))

def is_run_el(obj):
    """
    El objeto contiene el método ejecutable 'run'.
    """
    return hasattr(obj, 'run') and callable(getattr(obj, 'run'))

def difference(d1, d2, level=-1):
    """
    Devuelve un diccionario con los elementos de *d1* que no están contenidos en *d2*.

    El parámetro *level* establece la profundidad máxima de recursión. Para recursión infinita, configúralo en -1. Para un nivel 1, si una clave está presente tanto en *d1* como en *d2* pero tiene valores diferentes, se incluye en la diferencia. Consulta :func:`intersection` para más detalles.

    *d1* y *d2* permanecen sin cambios. Sin embargo, *d1* o algunos de sus subdiccionarios pueden ser devueltos directamente. Realiza una copia profunda del resultado cuando sea apropiado.

    .. versionadded:: 0.5  
       Agrega el argumento de palabra clave *level*.
    """
    result = {}

    # Iterar sobre todas las claves en d1
    for key in d1:
        # Si la clave no está en d2, incluir el valor completo de d1
        if key not in d2:
            result[key] = d1[key]
        # Si level no es 0 y ambos valores son diccionarios, hacer recursión
        elif level != 0 and isinstance(d1[key], dict) and isinstance(d2[key], dict):
            nested = difference(d1[key], d2[key], level - 1 if level > 0 else -1)
            if nested:
                result[key] = nested
        # Si los valores son diferentes y estamos en nivel 1 o superior
        elif d1[key] != d2[key]:
            result[key] = d1[key]

    return result

def _validate_labels(labels):
    import re
    from typing import Dict, Any

    # Expresión regular para validar claves de etiquetas
    KEY_REGEX = r'^[a-zA-Z][a-zA-Z0-9_-]*$'

    # Lista para almacenar los errores encontrados
    errors = []

    # Validar que labels sea un diccionario
    if not isinstance(labels, dict):
        raise ValidationError([{"labels": "se esperaba un diccionario"}])

    # Iterar sobre cada par clave-valor en las etiquetas
    for key, value in labels.items():

        # Validar que la clave sea una cadena
        if not isinstance(key, (str, bytes)):
            errors.append({
                str(key): 'se esperaba un objeto de tipo cadena o bytes'
            })
            continue

        # Validar que la clave coincida con la expresión regular
        if not re.match(KEY_REGEX, str(key)):
            errors.append({
                str(key): f"La clave de la etiqueta '{key}' no coincide con la expresión regular {KEY_REGEX}"
            })

        # Validar que el valor sea una cadena
        if not isinstance(value, (str, bytes)):
            errors.append({
                str(value): 'se esperaba un objeto de tipo cadena o bytes'
            })

    # Si hay errores, lanzar la excepción con todos los errores encontrados
    if errors:
        raise ValidationError(errors)

class ValidationError(Exception):
    def __init__(self, messages):
        self.messages = messages
        super().__init__(str(messages))

def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    observer_schema = {}

    # Process each key-value pair in the manifest dictionary
    for key, value in manifest_dict.items():

        # Handle first level identifiers
        if first_level and key in ['apiVersion', 'kind', 'metadata']:
            observer_schema[key] = value
            continue

        # Recursively process nested dictionaries
        if isinstance(value, dict):
            observer_schema[key] = generate_default_observer_schema_dict(value)

        # Recursively process lists    
        elif isinstance(value, list):
            from generate_default_observer_schema_list import generate_default_observer_schema_list
            observer_schema[key] = generate_default_observer_schema_list(value)

        # Set all other values to None    
        else:
            observer_schema[key] = None

    return observer_schema

def update_last_applied_manifest_list_from_resp(
    last_applied_manifest, observer_schema, response
):
    # Handle empty response
    if not response:
        return

    # Ensure last_applied_manifest has enough elements
    while len(last_applied_manifest) < len(response):
        last_applied_manifest.append({})

    # Update each element in the list
    for i, (schema_item, resp_item) in enumerate(zip(observer_schema, response)):
        # Handle dict items recursively
        if isinstance(schema_item, dict) and isinstance(resp_item, dict):
            if not isinstance(last_applied_manifest[i], dict):
                last_applied_manifest[i] = {}
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[i], schema_item, resp_item
            )
        # Handle list items recursively  
        elif isinstance(schema_item, list) and isinstance(resp_item, list):
            if not isinstance(last_applied_manifest[i], list):
                last_applied_manifest[i] = []
            update_last_applied_manifest_list_from_resp(
                last_applied_manifest[i], schema_item, resp_item
            )
        # Handle primitive values
        else:
            last_applied_manifest[i] = resp_item

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
):
    # Iterate through all fields in observer schema
    for field, value in observer_schema.items():
        # If field is not in response, raise KeyError
        if field not in response:
            raise KeyError(f"Field {field} not found in Kubernetes response")

        # If field not in last_applied_manifest, initialize it
        if field not in last_applied_manifest:
            if isinstance(value, dict):
                last_applied_manifest[field] = {}
                update_last_applied_manifest_dict_from_resp(
                    last_applied_manifest[field], value, response[field]
                )
            elif isinstance(value, list):
                last_applied_manifest[field] = []
                update_last_applied_manifest_list_from_resp(
                    last_applied_manifest[field], value[0], response[field]
                )
            else:
                last_applied_manifest[field] = response[field]

def generate_default_observer_schema(app):
    default_schema = {}

    # Check if app has manifest spec
    if not hasattr(app, 'spec') or not hasattr(app.spec, 'manifest'):
        return default_schema

    # Iterate through resources in manifest
    for resource in app.spec.manifest:
        # Skip if resource already has custom observer schema
        if resource.get('observer_schema'):
            continue

        # Get resource kind and API version
        kind = resource.get('kind')
        api_version = resource.get('apiVersion')

        if not kind or not api_version:
            continue

        # Generate default schema for this resource type
        resource_schema = {
            'type': 'object',
            'properties': {
                'status': {
                    'type': 'object',
                    'properties': {
                        'phase': {'type': 'string'},
                        'conditions': {
                            'type': 'array',
                            'items': {
                                'type': 'object',
                                'properties': {
                                    'type': {'type': 'string'},
                                    'status': {'type': 'string'},
                                    'reason': {'type': 'string'},
                                    'message': {'type': 'string'}
                                }
                            }
                        }
                    }
                }
            }
        }

        # Add schema to default_schema dict with resource type as key
        resource_key = f"{api_version}/{kind}"
        default_schema[resource_key] = resource_schema

    return default_schema

def formatmany(
        self,
        sql: AnyStr,
        many_params: Union[Iterable[Dict[Union[str, int], Any]], Iterable[Sequence[Any]]],
) -> Tuple[AnyStr, Union[List[Dict[Union[str, int], Any]], List[Sequence[Any]]]]:

    # Convert each params set to out style
    out_params = []
    for params in many_params:
        # Format single params set
        _, converted_params = self.format(sql, params)
        out_params.append(converted_params)

    # Format SQL once using first params set
    try:
        first_params = next(iter(many_params))
    except StopIteration:
        first_params = {}

    formatted_sql, _ = self.format(sql, first_params)

    return formatted_sql, out_params

def status_str(self, prefix=''):
    """
    Devuelve una cadena con el estado del validador, con un prefijo opcional.
    """
    status = []
    if hasattr(self, 'is_valid'):
        status.append('valid' if self.is_valid else 'invalid')
    if hasattr(self, 'errors') and self.errors:
        status.append(f'errors={len(self.errors)}')
    if hasattr(self, 'warnings') and self.warnings:
        status.append(f'warnings={len(self.warnings)}')

    status_text = ', '.join(status)
    if not status_text:
        status_text = 'empty'

    return f'{prefix}[{status_text}]'

def status_str(self, prefix=''):
    """
    Devuelve la representación en forma de cadena del registro de validación, con un prefijo opcional.
    """
    result = []
    if self.errors:
        result.append(f"{prefix}Errores:")
        for error in self.errors:
            result.append(f"{prefix}  {error}")

    if self.warnings:
        result.append(f"{prefix}Advertencias:")
        for warning in self.warnings:
            result.append(f"{prefix}  {warning}")

    if not result:
        result.append(f"{prefix}Sin errores ni advertencias")

    return "\n".join(result)

def validate(self, inventory, extract_spec_version=False):
    """
    Validar un inventario dado.

    Si `extract_spec_version` es True, entonces se verificará el valor de `type` para determinar
    la versión de la especificación. En el caso de que no exista un valor para `type` o no sea
    válido, se realizarán otras pruebas basadas en la versión proporcionada en `self.spec_version`.
    """
    if not isinstance(inventory, dict):
        raise ValueError("El inventario debe ser un diccionario")

    if extract_spec_version:
        try:
            inventory_type = inventory.get('type', '')
            if inventory_type.startswith('inventory/'):
                self.spec_version = inventory_type.split('/')[1]
            else:
                # Si no hay un tipo válido, usar la versión por defecto
                pass
        except (AttributeError, IndexError):
            # Si hay algún error al extraer la versión, usar la versión por defecto
            pass

    # Validar campos requeridos básicos
    required_fields = ['id', 'items']
    for field in required_fields:
        if field not in inventory:
            raise ValueError(f"Campo requerido '{field}' no encontrado en el inventario")

    # Validar que items sea una lista
    if not isinstance(inventory['items'], list):
        raise ValueError("El campo 'items' debe ser una lista")

    # Validar cada item en el inventario
    for item in inventory['items']:
        if not isinstance(item, dict):
            raise ValueError("Cada item debe ser un diccionario")

        # Validar campos requeridos para cada item
        item_required_fields = ['id', 'quantity']
        for field in item_required_fields:
            if field not in item:
                raise ValueError(f"Campo requerido '{field}' no encontrado en un item")

        # Validar tipos de datos
        if not isinstance(item['id'], str):
            raise ValueError("El campo 'id' del item debe ser una cadena de texto")
        if not isinstance(item['quantity'], (int, float)):
            raise ValueError("El campo 'quantity' del item debe ser un número")

    return True

def validate_as_prior_version(self, prior):
    # Verificar que prior sea una instancia de InventoryValidator
    if not isinstance(prior, type(self)):
        raise TypeError("El inventario previo debe ser del mismo tipo")

    # Verificar que la fecha del prior sea anterior
    if prior.date >= self.date:
        raise ValueError("La fecha del inventario previo debe ser anterior")

    # Verificar que los productos existentes en prior existan en self
    # con cantidades mayores o iguales
    for product_id, prior_qty in prior.quantities.items():
        if product_id not in self.quantities:
            raise ValueError(f"Producto {product_id} no existe en inventario actual")
        if self.quantities[product_id] < prior_qty:
            raise ValueError(f"Cantidad actual de {product_id} es menor que en versión previa")

    # Verificar que los IDs de productos sean consistentes
    if not set(prior.products.keys()).issubset(set(self.products.keys())):
        raise ValueError("Los productos del inventario previo deben existir en el actual")

    # Si pasa todas las validaciones, retornar True
    return True

def get_logical_path_map(inventory, version):
    logical_path_map = {}

    # Iterate through all versions up to and including target version
    for v in range(version + 1):
        if v in inventory:
            # For each file in this version
            for logical_path, content_file in inventory[v].items():
                # Initialize set if logical path not seen before
                if logical_path not in logical_path_map:
                    logical_path_map[logical_path] = set()

                # Add content file to set for this logical path
                logical_path_map[logical_path].add(content_file)

    return logical_path_map

def validate_fixity(self, fixity, manifest_files):
    """
    Validar el bloque de fijación en el inventario.

    Verificar la estructura del bloque de fijación y asegurarse de que solo se referencien los archivos listados en el manifiesto.
    """
    if not isinstance(fixity, dict):
        raise ValueError("El bloque de fijación debe ser un diccionario")

    # Verificar que tenga las claves requeridas
    required_keys = ["message_digest_algorithm", "message_digest"]
    for key in required_keys:
        if key not in fixity:
            raise ValueError(f"Falta la clave requerida '{key}' en el bloque de fijación")

    # Verificar que el algoritmo sea válido
    valid_algorithms = ["md5", "sha1", "sha256", "sha512"]
    if fixity["message_digest_algorithm"].lower() not in valid_algorithms:
        raise ValueError(f"Algoritmo de digest no válido. Debe ser uno de: {valid_algorithms}")

    # Verificar que message_digest sea un diccionario
    if not isinstance(fixity["message_digest"], dict):
        raise ValueError("message_digest debe ser un diccionario")

    # Verificar que solo se referencien archivos del manifiesto
    for file_path in fixity["message_digest"]:
        if file_path not in manifest_files:
            raise ValueError(f"El archivo '{file_path}' en el bloque de fijación no está listado en el manifiesto")

    # Verificar que los digests sean strings no vacíos
    for file_path, digest in fixity["message_digest"].items():
        if not isinstance(digest, str) or not digest:
            raise ValueError(f"Digest inválido para el archivo '{file_path}'")

    return True

def select_filenames_by_prefix(prefix, files):
    selected_files = []

    for file in files:
        # Get just the filename without path
        filename = file.split('/')[-1]

        # Check if filename starts with prefix
        if filename.startswith(prefix):
            selected_files.append(file)

    return selected_files

def add_rendition(self, lang, file_path):
    """
    Adds a rendition file path for a specific language to the renditions dictionary.

    Args:
        lang (str): Language code for the rendition (e.g. 'en', 'es')
        file_path (str): Path to the rendition file

    Returns:
        None

    Example:
    {
        "original": "artigo02.pdf",
        "en": "artigo02-en.pdf",
    }
    """
    if not hasattr(self, 'renditions'):
        self.renditions = {}

    if lang == 'original':
        self.renditions['original'] = file_path
    else:
        self.renditions[lang] = file_path

def fix_namespace_prefix_w(content):
    """
    Convierte el texto que por defecto es 'w:st="' a 'w-st="'
    """
    return content.replace('w:st="', 'w-st="')

def match_pubdate(node, pubdate_xpaths):
    """
    Devuelve la primera coincidencia en la lista de 'pubdate_xpaths'.
    """
    for xpath in pubdate_xpaths:
        match = node.xpath(xpath)
        if match:
            return match[0]
    return None

def on(self, hook):
    def decorator(listener):
        if hook not in self._listeners:
            self._listeners[hook] = []
        self._listeners[hook].append(listener)
        return listener
    return decorator

def base_config(user, etcd_host="localhost", etcd_port=2379):
    """
    Crea una configuración con algunos parámetros simples, los cuales tienen un valor predeterminado que puede ser configurado.

    Argumentos:
    user (str): el nombre del usuario para la autenticación estática.
    etcd_host (str): el host para la base de datos.
    etcd_port (int): el puerto para la base de datos.

    Retorna:
    dict: la configuración creada.
    """
    config = {
        "auth": {
            "user": user,
            "type": "static"
        },
        "database": {
            "host": etcd_host,
            "port": etcd_port,
            "type": "etcd"
        }
    }

    return config

def get_versions():
    """
    Obtén la información de la versión o devuelve el valor predeterminado si no es posible obtenerla.
    """
    try:
        import pkg_resources
        import platform
        import sys

        versions = {
            'python': sys.version.split()[0],
            'platform': platform.platform(),
            'packages': {
                pkg.key: pkg.version 
                for pkg in pkg_resources.working_set
            }
        }

        return versions

    except Exception:
        # Return default version info if unable to get actual versions
        return {
            'python': 'unknown',
            'platform': 'unknown',
            'packages': {}
        }

def render(pieces, style):
    """
    Renderiza las piezas de versión dadas en el estilo solicitado.
    """
    rendered = []

    for piece in pieces:
        if style == "dots":
            rendered.append(piece.replace(".", "•"))
        elif style == "arrows":
            rendered.append(piece.replace("<", "←").replace(">", "→"))
        elif style == "unicode":
            rendered.append(piece.replace("-", "─").replace("|", "│"))
        else:
            rendered.append(piece)

    return rendered

def run_command(commands, args, cwd=None, verbose=False, hide_stderr=False, env=None):
    """
    Llama al/los comando(s) dado(s).
    """
    import subprocess
    import sys

    if isinstance(commands, str):
        commands = [commands]

    for cmd in commands:
        cmd_list = [cmd]
        if args:
            if isinstance(args, str):
                cmd_list.append(args)
            else:
                cmd_list.extend(args)

        if verbose:
            print(' '.join(cmd_list))

        stderr = subprocess.DEVNULL if hide_stderr else None

        try:
            subprocess.check_call(cmd_list, cwd=cwd, stderr=stderr, env=env)
        except subprocess.CalledProcessError as e:
            sys.exit(e.returncode)
        except OSError as e:
            sys.exit(e.errno)

def validate_hierarchy(self, validate_objects=True, check_digests=True, show_warnings=False):
    """
    Validar la jerarquía de la raíz de almacenamiento.

    Retorna:
        num_objects - número de objetos verificados
        good_objects - número de objetos verificados que se encontraron válidos
    """
    num_objects = 0
    good_objects = 0

    # Recorrer recursivamente la jerarquía
    for root, dirs, files in self.walk():
        for file in files:
            num_objects += 1

            try:
                # Validar objeto si está habilitado
                if validate_objects:
                    obj = self.get_object(file)

                    # Verificar digests si está habilitado
                    if check_digests:
                        if obj.verify_digest():
                            good_objects += 1
                        elif show_warnings:
                            print(f"Warning: Invalid digest for {file}")
                    else:
                        good_objects += 1

            except Exception as e:
                if show_warnings:
                    print(f"Warning: Error validating {file}: {str(e)}")
                continue

    return num_objects, good_objects

def find_path_type(path):
    import os
    import glob

    # Check if path exists
    if not os.path.exists(path):
        return "Error: Path does not exist"

    # Check if it's a directory
    if not os.path.isdir(path):
        if os.path.isfile(path):
            return "file"
        return "Error: Path is neither file nor directory"

    # Look for Namaste files starting with "0="
    namaste_files = glob.glob(os.path.join(path, "0=*"))

    if not namaste_files:
        return "Error: No Namaste files found"

    # Read content of first Namaste file
    try:
        with open(namaste_files[0], 'r') as f:
            content = f.read().strip()

        # Check content for OCFL root
        if "ocfl_" in content.lower():
            return "root"

        # Check content for OCFL object
        elif "object" in content.lower():
            return "object"

    except Exception as e:
        return f"Error reading Namaste file: {str(e)}"

    return "Error: Unknown Namaste file type"

def amend_bzparams(self, params, bug_ids):
    """
    Modificar los parámetros de Bugzilla
    """
    if not params:
        params = {}

    if bug_ids:
        if isinstance(bug_ids, (list, tuple)):
            params['bug_id'] = bug_ids
        else:
            params['bug_id'] = [bug_ids]

    if 'include_fields' not in params:
        params['include_fields'] = ['id', 'summary', 'status', 'resolution', 
                                  'creator', 'assigned_to', 'creation_time',
                                  'last_change_time', 'component', 'product']

    if 'exclude_fields' not in params:
        params['exclude_fields'] = []

    return params

def deep_merge_nodes(nodes):
    result = {}

    # Iterate through all nodes and merge them
    for key_node, value_node in nodes:
        key = key_node.value

        # If key doesn't exist yet, just add it
        if key not in result:
            result[key] = (key_node, value_node)
            continue

        # If key exists, need to merge values
        existing_value = result[key][1]

        # If both nodes are mapping nodes, merge them recursively
        if (isinstance(existing_value, type(value_node)) and 
            hasattr(existing_value, 'value') and 
            hasattr(value_node, 'value')):

            # Create dict of existing key-value pairs
            existing_dict = {k.value: (k,v) for k,v in existing_value.value}

            # Merge in new key-value pairs
            for k, v in value_node.value:
                existing_dict[k.value] = (k,v)

            # Create new MappingNode with merged values
            merged_value = type(value_node)(
                tag=value_node.tag,
                value=list(existing_dict.values())
            )
            result[key] = (key_node, merged_value)

        # If not both mapping nodes, take the latest value
        else:
            result[key] = (key_node, value_node)

    return list(result.values())

def parser_flags(parser):
    flags = []
    for action in parser._actions:
        # Skip the default help action
        if action.dest == 'help':
            continue
        # Add all option strings (flags) for this argument
        flags.extend(action.option_strings)
    # Return flags joined by spaces
    return ' '.join(sorted(flags))

def parse_arguments(*unparsed_arguments):
    import argparse

    # Create main parser
    parser = argparse.ArgumentParser(description='Command line argument parser')

    # Add global arguments that apply to all subcommands
    parser.add_argument('--verbose', '-v', action='store_true', help='Enable verbose output')

    # Create subparsers object to handle subcommands
    subparsers = parser.add_subparsers(dest='command')

    # Initialize dictionary to store parsed arguments
    parsed_args = {}

    # If no arguments provided, show help and exit
    if not unparsed_arguments:
        parser.print_help()
        return {}

    try:
        # Parse the arguments
        args = parser.parse_args(unparsed_arguments[0])

        # Store global arguments
        parsed_args['global'] = args

        # Store subcommand arguments if a subcommand was used
        if args.command:
            parsed_args[args.command] = args

        return parsed_args

    except Exception as e:
        parser.print_help()
        return {}

def parse_subparser_arguments(unparsed_arguments, subparsers):
    """
    Dada una secuencia de argumentos y un diccionario que mapea el nombre de un subparser a una instancia de `argparse.ArgumentParser`, permite que cada subparser solicitado intente analizar todos los argumentos. Esto permite que argumentos comunes como `--repository` sean compartidos entre múltiples subparsers.

    Devuelve el resultado como una tupla que contiene: 
    - Un diccionario que mapea el nombre del subparser a un espacio de nombres (`namespace`) de argumentos analizados.
    - Una lista de argumentos restantes que no fueron reclamados por ningún subparser.
    """
    parsed_args = {}
    remaining_args = list(unparsed_arguments)

    # Iterate through each subparser
    for name, subparser in subparsers.items():
        try:
            # Try to parse all remaining arguments with current subparser
            namespace, leftover = subparser.parse_known_args(remaining_args)
            parsed_args[name] = namespace
            remaining_args = leftover
        except:
            # If parsing fails, skip this subparser
            continue

    return parsed_args, remaining_args

def deep_merge_nodes(nodes):
    merged = {}

    # Iterate through nodes in reverse so later values take precedence
    for key_node, value_node in reversed(nodes):
        key = key_node.value

        if key not in merged:
            # First time seeing this key, just store the nodes
            merged[key] = (key_node, value_node)
            continue

        # Key exists, need to merge
        existing_value_node = merged[key][1]

        # If both are mapping nodes, merge them recursively
        if (hasattr(value_node, 'tag') and 'map' in value_node.tag and 
            hasattr(existing_value_node, 'tag') and 'map' in existing_value_node.tag):

            # Convert mapping node values to dict for easier lookup
            existing_dict = {k.value: (k,v) for k,v in existing_value_node.value}
            new_dict = {k.value: (k,v) for k,v in value_node.value}

            # Merge the mapping values
            for new_key, new_pair in new_dict.items():
                if new_key not in existing_dict:
                    existing_dict[new_key] = new_pair
                else:
                    # Recursively merge if both are mapping nodes
                    if ('map' in new_pair[1].tag and 
                        'map' in existing_dict[new_key][1].tag):
                        merged_value = deep_merge_nodes([
                            (existing_dict[new_key][0], existing_dict[new_key][1]),
                            (new_pair[0], new_pair[1])
                        ])
                        existing_dict[new_key] = merged_value[0]
                    else:
                        # For non-mapping nodes, take the newer value
                        existing_dict[new_key] = new_pair

            # Convert back to list of tuples
            merged_value = list(existing_dict.values())

            # Create new mapping node with merged values
            merged[key] = (key_node, type(value_node)(tag=value_node.tag, value=merged_value))

        else:
            # For non-mapping nodes, take the newer value
            merged[key] = (key_node, value_node)

    return list(merged.values())

def parser_flags(parser):
    flags = []
    for action in parser._actions:
        # Skip the default help action
        if action.dest == 'help':
            continue
        # Add all option strings (flags) for this argument
        flags.extend(action.option_strings)
    # Return flags joined by spaces
    return ' '.join(sorted(flags))

def parse_subparser_arguments(unparsed_arguments, subparsers):
    """
    Dada una secuencia de argumentos y un diccionario que mapea el nombre de un subparser a una instancia de `argparse.ArgumentParser`, permite que cada subparser solicitado intente analizar todos los argumentos. Esto permite que argumentos comunes como "--repository" sean compartidos entre múltiples subparsers.

    Devuelve el resultado como una tupla que contiene: (un diccionario que mapea el nombre del subparser a un espacio de nombres (`namespace`) de argumentos analizados, una lista de argumentos restantes que no fueron reclamados por ningún subparser).
    """
    parsed_args = {}
    remaining_args = list(unparsed_arguments)

    # Iterate through each subparser
    for subparser_name, subparser in subparsers.items():
        try:
            # Try to parse all remaining arguments with current subparser
            namespace, leftover = subparser.parse_known_args(remaining_args)

            # Store successfully parsed arguments for this subparser
            parsed_args[subparser_name] = namespace

            # Update remaining arguments to only those that weren't parsed
            remaining_args = leftover

        except Exception:
            # If parsing fails, continue to next subparser
            continue

    return parsed_args, remaining_args

def _dictsum(dicts):
    result = {}
    for d in dicts:
        for key, value in d.items():
            if key in result:
                result[key] += value
            else:
                result[key] = value
    return result

def _replace_url_args(url, url_args):
    """
    Reemplace cualquier elemento personalizado de la URL con los valores en `args`.
    """
    if not url_args:
        return url

    for key, value in url_args.items():
        if value is not None:
            placeholder = '{' + key + '}'
            url = url.replace(placeholder, str(value))

    return url

def int_to_string(number: int, alphabet: List[str], padding: Optional[int] = None) -> str:
    # Manejo del caso especial cuando el número es 0
    if number == 0:
        result = alphabet[0]
        if padding:
            result = result.rjust(padding, alphabet[0])
        return result

    # Convertir el número usando el alfabeto dado
    base = len(alphabet)
    result = ""

    # Convertir el número a la base del alfabeto
    n = abs(number)
    while n:
        result = alphabet[n % base] + result
        n //= base

    # Agregar el signo negativo si es necesario
    if number < 0:
        result = '-' + result

    # Agregar padding si se especifica
    if padding:
        if number < 0:
            # Si es negativo, el padding va después del signo
            result = '-' + result[1:].rjust(padding, alphabet[0])
        else:
            result = result.rjust(padding, alphabet[0])

    return result

def _replace_register(flow_params, register_number, register_value):
    """
    Reemplazar el valor de los flujos al número de registro dado

    La clave 'register_value' en el diccionario será reemplazada por el número de registro proporcionado por 'register_number'

    :param flow_params: Diccionario que contiene los flujos definidos  
    :param register_number: El número del registro donde se almacenará el valor  
    :param register_value: Clave que será reemplazada por el número de registro  
    """
    # Recorrer el diccionario de manera recursiva
    for key, value in flow_params.items():
        # Si el valor es un diccionario, llamar recursivamente
        if isinstance(value, dict):
            _replace_register(value, register_number, register_value)
        # Si el valor es una lista, revisar cada elemento
        elif isinstance(value, list):
            for i, item in enumerate(value):
                if isinstance(item, dict):
                    _replace_register(item, register_number, register_value)
        # Si el valor coincide con register_value, reemplazarlo
        elif value == register_value:
            flow_params[key] = register_number

def replace_dots(value, arg):
    """
    Reemplaza todos los valores de '.' por el argumento proporcionado en la cadena dada.
    """
    return value.replace('.', str(arg))

def unquote(name):
    """
    Eliminar comillas del nombre dado.
    """
    return name.replace('"', '').replace("'", "")

def parse_frequency(frequency):
    from datetime import timedelta

    if frequency is None or frequency.lower() == "always":
        return None

    try:
        # Split into number and unit
        parts = frequency.strip().split()
        if len(parts) != 2:
            raise ValueError(f"Invalid frequency format: {frequency}")

        number = float(parts[0])
        unit = parts[1].lower()

        # Map units to timedelta parameters
        unit_mapping = {
            'second': 'seconds',
            'seconds': 'seconds',
            'minute': 'minutes', 
            'minutes': 'minutes',
            'hour': 'hours',
            'hours': 'hours',
            'day': 'days',
            'days': 'days',
            'week': 'weeks',
            'weeks': 'weeks'
        }

        if unit not in unit_mapping:
            raise ValueError(f"Invalid time unit: {unit}")

        # Create timedelta with the appropriate parameter
        kwargs = {unit_mapping[unit]: number}
        return timedelta(**kwargs)

    except (ValueError, TypeError) as e:
        raise ValueError(f"Could not parse frequency: {frequency}") from e

def get_pattern(pattern, strip=True):
    """
    Este método convierte la cadena proporcionada en un objeto de patrón regex.
    """
    import re

    if strip:
        pattern = pattern.strip()

    try:
        return re.compile(pattern)
    except re.error:
        return None

def run_command(commands, args, cwd=None, verbose=False, hide_stderr=False, env=None):
    """
    Llama al/los comando(s) dado(s).
    """
