            subprocess.check_call(cmd_list, cwd=cwd, stderr=stderr, env=env)
        except subprocess.CalledProcessError as e:
            sys.exit(e.returncode)
        except OSError as e:
            sys.exit(e.errno)

def _dump_string(obj, dumper=None):
    """
    Volcar a una cadena en formato py2-unicode o py3-string
    """
    if isinstance(obj, str):
        return obj
    elif isinstance(obj, bytes):
        return obj.decode('utf-8')
    else:
        return str(obj)

def load_configurations(config_filenames, overrides=None, resolve_env=True):
    """
    Dada una secuencia de nombres de archivo de configuración, carga y valida cada archivo de configuración. Si el archivo de configuración no puede ser leído debido a permisos insuficientes o errores al analizar el archivo de configuración, se registrará el error en el log. De lo contrario, devuelve los resultados como una tupla que contiene: un diccionario que asocia el nombre del archivo de configuración con su configuración analizada correspondiente, y una secuencia de instancias de `logging.LogRecord` que contienen cualquier error de análisis.
    """
    import logging
    import os
    import yaml
    from pathlib import Path

    # Initialize return values
    configs = {}
    error_logs = []
    logger = logging.getLogger(__name__)

    # Process each config file
    for filename in config_filenames:
        try:
            path = Path(filename)

            # Check if file exists and is readable
            if not path.exists():
                raise FileNotFoundError(f"Configuration file not found: {filename}")

            if not os.access(path, os.R_OK):
                raise PermissionError(f"Insufficient permissions to read: {filename}")

            # Load and parse YAML file
            with open(path, 'r') as f:
                config = yaml.safe_load(f)

            # Apply environment variable resolution if requested
            if resolve_env:
                config = resolve_environment_variables(config)

            # Apply overrides if provided
            if overrides and isinstance(overrides, dict):
                config = deep_update(config, overrides)

            configs[filename] = config

        except (FileNotFoundError, PermissionError, yaml.YAMLError) as e:
            error_record = logging.LogRecord(
                name=__name__,
                level=logging.ERROR,
                pathname=filename,
                lineno=0,
                msg=str(e),
                args=(),
                exc_info=None
            )
            error_logs.append(error_record)
            logger.error(f"Error loading configuration file {filename}: {str(e)}")

    return configs, error_logs

def resolve_environment_variables(config):
    """Helper function to resolve environment variables in config"""
    import os

    if isinstance(config, dict):
        return {k: resolve_environment_variables(v) for k, v in config.items()}
    elif isinstance(config, list):
        return [resolve_environment_variables(v) for v in config]
    elif isinstance(config, str) and config.startswith('${') and config.endswith('}'):
        env_var = config[2:-1]
        return os.environ.get(env_var, config)
    return config

def deep_update(original, update):
    """Helper function to recursively update nested dictionaries"""
    for key, value in update.items():
        if isinstance(value, dict) and key in original and isinstance(original[key], dict):
            deep_update(original[key], value)
        else:
            original[key] = value
    return original

def force_string(obj):
    """
    Esta función devuelve el objeto de tipo `bytes` correspondiente a ``obj`` en caso de que sea una cadena utilizando UTF-8.
    """
    if isinstance(obj, str):
        return obj.encode('utf-8')
    return obj

def protocol_handlers(cls, protocol_version=None):
    # Diccionario de controladores de protocolo disponibles
    handlers = {
        (3, 0): BoltProtocolV3,
        (4, 0): BoltProtocolV4,
        (4, 1): BoltProtocolV4_1,
        (4, 2): BoltProtocolV4_2,
        (4, 3): BoltProtocolV4_3,
        (4, 4): BoltProtocolV4_4,
        (5, 0): BoltProtocolV5
    }

    # Si no se especifica versión, devolver todos los controladores
    if protocol_version is None:
        return handlers

    # Validar que la versión sea una tupla
    if not isinstance(protocol_version, tuple):
        raise TypeError("La versión del protocolo debe ser una tupla")

    # Si se especifica versión, devolver solo el controlador para esa versión
    if protocol_version in handlers:
        return {protocol_version: handlers[protocol_version]}

    # Si la versión no existe, devolver diccionario vacío
    return {}

def from_raw_values(cls, values):
    """
    Crear un objeto "Bookmarks" a partir de una lista de valores de marcadores en formato de cadena sin procesar.

    No deberías necesitar usar este método a menos que desees deserializar marcadores.

    :param values: Valores de cadenas ASCII (marcadores sin procesar)
    :type values: Iterable[str]
    """
    bookmarks = []
    for value in values:
        try:
            # Remove any whitespace and validate string is not empty
            bookmark = value.strip()
            if bookmark:
                bookmarks.append(bookmark)
        except (AttributeError, TypeError):
            # Skip invalid values that can't be converted to string
            continue

    return cls(bookmarks)

def _get_seq_with_type(seq, bufsize=None):
    """
    Devuelve un par (secuencia, tipo).
    La secuencia se deriva de *seq*
    (o es *seq*, si este es de un tipo de secuencia).
    """
    # Check if seq is already a sequence type
    if isinstance(seq, (list, tuple, bytes, bytearray)):
        return seq, type(seq)

    # Convert iterables to list
    if hasattr(seq, '__iter__'):
        if bufsize is None:
            return list(seq), list
        else:
            # If bufsize specified, only take that many items
            return list(itertools.islice(seq, bufsize)), list

    # Convert single items to single-item list
    return [seq], list

def scale(self, other=None):
    if other is None:
        return self._scale

    if not isinstance(other, (int, float)):
        raise TypeError("Scale must be a numeric value")

    if self._scale is None or self._scale == 0:
        raise LenaValueError("Cannot rescale graph with unknown or zero scale")

    # Get the scale factor
    factor = other / self._scale

    # Get the last coordinate index
    last_coord = len(self.coordinates) - 1

    # Rescale the last coordinate and its errors
    self.coordinates[last_coord] *= factor

    if hasattr(self, 'errors') and self.errors is not None:
        for error in self.errors:
            if error is not None and last_coord < len(error):
                error[last_coord] *= factor

    # Update the scale
    self._scale = other

    return self._scale

def hist_to_graph(hist, make_value=None, get_coordinate="left",
                  field_names=("x", "y"), scale=None):
    # Default make_value function just returns bin content
    if make_value is None:
        make_value = lambda x: x

    # Get coordinate function based on parameter
    if get_coordinate == "left":
        get_coord = lambda bin: bin.left
    elif get_coordinate == "right":
        get_coord = lambda bin: bin.right
    elif get_coordinate == "middle":
        get_coord = lambda bin: (bin.left + bin.right) / 2
    else:
        raise ValueError("get_coordinate must be 'left', 'right' or 'middle'")

    # Create points list
    points = []
    for bin in hist:
        x = get_coord(bin)
        y = make_value(bin.content)

        # Handle both single values and tuples returned by make_value
        if isinstance(y, (tuple, list)):
            points.append((x,) + tuple(y))
        else:
            points.append((x, y))

    # Validate field names match point dimensions
    point_dim = len(points[0])
    if len(field_names) != point_dim:
        raise ValueError(f"Number of field names ({len(field_names)}) must match point dimension ({point_dim})")

    # Create graph with appropriate scale
    from .graph import Graph
    graph = Graph(points, field_names=field_names)

    if scale is True:
        graph.scale = hist.scale
    elif scale is not None:
        graph.scale = scale

    return graph

def _verify(iface, candidate, tentative=False, vtype=None):
    from zope.interface.exceptions import Invalid
    from zope.interface.interface import Method
    from collections import defaultdict

    errors = defaultdict(list)

    # Check if candidate claims to provide interface
    if not tentative and not iface.providedBy(candidate):
        errors['general'].append(
            f"Class {candidate.__class__.__name__} does not implement interface {iface.__name__}"
        )

    # Check methods
    for name, desc in iface.namesAndDescriptions(1):
        if isinstance(desc, Method):
            # Check if method exists
            if not hasattr(candidate, name):
                errors['methods'].append(
                    f"Method '{name}' not provided by {candidate.__class__.__name__}"
                )
                continue

            method = getattr(candidate, name)
            if not callable(method):
                errors['methods'].append(
                    f"Attribute '{name}' is not callable as required"
                )
                continue

            # Check method signature if possible
            try:
                import inspect
                impl_sig = inspect.signature(method)
                iface_sig = inspect.signature(desc)

                if impl_sig.parameters != iface_sig.parameters:
                    errors['methods'].append(
                        f"Method '{name}' has incorrect signature. "
                        f"Expected {iface_sig}, got {impl_sig}"
                    )
            except (ValueError, TypeError):
                pass  # Skip signature checking if not possible

        else:  # Attribute
            if not hasattr(candidate, name):
                errors['attributes'].append(
                    f"Attribute '{name}' not provided by {candidate.__class__.__name__}"
                )

    # If there are any errors, raise them
    if errors:
        all_errors = []
        for category, category_errors in errors.items():
            all_errors.extend(category_errors)

        if len(all_errors) == 1:
            raise Invalid(all_errors[0])
        elif all_errors:
            raise Invalid('\n'.join(all_errors))

    return True

def verifyObject(iface, candidate, tentative=False):
    from zope.interface.exceptions import Invalid, DoesNotImplement, BrokenImplementation, BrokenMethodImplementation
    from zope.interface.interface import Method

    errors = []

    # Verify interface is provided
    if not tentative and not iface.providedBy(candidate):
        errors.append(DoesNotImplement(iface))

    # Verify methods and attributes
    for name, desc in iface.namesAndDescriptions(1):
        try:
            attr = getattr(candidate, name)
        except AttributeError:
            errors.append(BrokenImplementation(iface, name))
            continue

        # Verify methods
        if isinstance(desc, Method):
            if not callable(attr):
                errors.append(BrokenMethodImplementation(name, "Not callable"))
                continue

            # Verify method signature
            try:
                from inspect import signature
                method_sig = signature(attr)
                interface_sig = signature(desc)

                if len(method_sig.parameters) != len(interface_sig.parameters):
                    errors.append(BrokenMethodImplementation(
                        name,
                        f"Incorrect number of arguments: expected {len(interface_sig.parameters)}, got {len(method_sig.parameters)}"
                    ))
            except ValueError:
                # Can't verify signature, skip
                pass

    # Handle errors
    if len(errors) == 1:
        raise errors[0]
    elif errors:
        raise Invalid(errors)

    return True

def determineMetaclass(bases, explicit_mc=None):
    """
    Determina la metaclase a partir de una o más clases base y un __metaclass__ explícito opcional.
    """
    metaclasses = []

    # Agregar metaclase explícita si existe
    if explicit_mc is not None:
        metaclasses.append(explicit_mc)

    # Obtener metaclases de las clases base
    for base in bases:
        if hasattr(base, '__class__'):
            metaclasses.append(type(base))

    if not metaclasses:
        return type

    # Si solo hay una metaclase, retornarla
    if len(metaclasses) == 1:
        return metaclasses[0]

    # Si hay múltiples metaclases, encontrar la más específica
    candidate = metaclasses[0]
    for mc in metaclasses[1:]:
        if issubclass(candidate, mc):
            continue
        if issubclass(mc, candidate):
            candidate = mc
        else:
            raise TypeError("Conflicting metaclasses:", candidate, mc)

    return candidate

def pop(self, key, default=__marker):
    """
    D.pop(k[,d]) -> v, elimina la clave especificada y devuelve el valor correspondiente.
    Si la clave no se encuentra, se devuelve `d` si se proporciona; de lo contrario, se genera una excepción KeyError.
    """
    try:
        value = self[key]
        del self[key]
        return value
    except KeyError:
        if default is __marker:
            raise KeyError(key)
        return default

def identify_request(request: RequestType):
    # Try to identify if it's a public message
    if hasattr(request, 'entity_type') and request.entity_type == 'status_message':
        return 'public'

    # Try to identify if it's a private message
    if hasattr(request, 'aes_key') or hasattr(request, 'encrypted_magic_envelope'):
        return 'private'

    # Check if it's a legacy payload by looking for old format indicators
    if hasattr(request, 'xml_payload') or hasattr(request, 'legacy_format'):
        return 'legacy'

    # If we can't identify the request type
    return 'unknown'

def format_dt(dt):
    """
    Formatea un objeto `datetime` en el formato que los nodos D* esperan.
    """
    return dt.strftime("%Y-%m-%d %H:%M:%S")

def parse_diaspora_webfinger(document: str) -> Dict:
    """
    Analiza el webfinger de Diaspora, que puede estar en formato JSON (nuevo) o en formato XRD (antiguo).

    Args:
        document: String containing the webfinger document in JSON or XRD format

    Returns:
        Dictionary with parsed webfinger data
    """
    import json
    import xml.etree.ElementTree as ET
    from typing import Dict

    # Try parsing as JSON first
    try:
        data = json.loads(document)
        result = {
            'subject': data.get('subject', ''),
            'aliases': data.get('aliases', []),
            'links': []
        }

        # Parse links
        for link in data.get('links', []):
            link_data = {
                'rel': link.get('rel', ''),
                'href': link.get('href', ''),
                'type': link.get('type', '')
            }
            result['links'].append(link_data)

        return result

    except json.JSONDecodeError:
        # If JSON fails, try parsing as XML/XRD
        try:
            root = ET.fromstring(document)

            # Define XML namespaces
            ns = {
                'xrd': 'http://docs.oasis-open.org/ns/xri/xrd-1.0',
                'hm': 'http://host-meta.net/xrd/1.0'
            }

            result = {
                'subject': '',
                'aliases': [],
                'links': []
            }

            # Get subject
            subject = root.find('.//xrd:Subject', ns)
            if subject is not None:
                result['subject'] = subject.text

            # Get aliases
            for alias in root.findall('.//xrd:Alias', ns):
                if alias.text:
                    result['aliases'].append(alias.text)

            # Get links
            for link in root.findall('.//xrd:Link', ns):
                link_data = {
                    'rel': link.get('rel', ''),
                    'href': link.get('href', ''),
                    'type': link.get('type', '')
                }
                result['links'].append(link_data)

            return result

        except ET.ParseError:
            raise ValueError("Document is neither valid JSON nor valid XML/XRD format")

def dict_insert(dic, val, key, *keys):
    if not keys:
        dic[key] = val
        return dic

    if key not in dic:
        dic[key] = {}

    current = dic[key]
    for k in keys[:-1]:
        if k not in current:
            current[k] = {}
        current = current[k]

    current[keys[-1]] = val
    return dic

def ansible_config_manager(cls):
    """
    Obtiene el administrador de configuración de Ansible.
    """
    from ansible.config.manager import ConfigManager
    return ConfigManager()

def validate_from_content(cls, spec_content=None):
    """
    Valida que el contenido del archivo spec (YAML) tenga todos los campos requeridos.

    :param spec_content: contenido del archivo spec
    :raise IRValidatorException: cuando faltan datos obligatorios
    en el archivo spec
    :return: Diccionario con los datos cargados desde un archivo spec (YAML)
    """
    if spec_content is None:
        raise IRValidatorException("El contenido del archivo spec no puede estar vacío")

    required_fields = ['name', 'version', 'description', 'author']

    for field in required_fields:
        if field not in spec_content:
            raise IRValidatorException(f"Campo requerido '{field}' no encontrado en el archivo spec")

    # Validaciones adicionales específicas
    if not isinstance(spec_content['version'], (int, float, str)):
        raise IRValidatorException("El campo 'version' debe ser un número o string")

    if not isinstance(spec_content['description'], str):
        raise IRValidatorException("El campo 'description' debe ser un string")

    if not isinstance(spec_content['author'], str):
        raise IRValidatorException("El campo 'author' debe ser un string")

    # Si todas las validaciones pasan, retornar el contenido validado
    return spec_content

def validate_from_file(cls, yaml_file=None):
    """
    Carga y valida que un archivo YAML contenga todos los campos requeridos.

    :param yaml_file: Ruta al archivo YAML
    :raise IRValidatorException: cuando faltan datos obligatorios en el archivo 
    :return: Diccionario con los datos cargados desde un archivo YAML
    """
    try:
        import yaml

        if yaml_file is None:
            raise IRValidatorException("No se especificó un archivo YAML")

        with open(yaml_file, 'r') as f:
            data = yaml.safe_load(f)

        if not isinstance(data, dict):
            raise IRValidatorException("El archivo YAML debe contener un diccionario")

        required_fields = ['name', 'version', 'description']  # Campos requeridos ejemplo

        missing_fields = [field for field in required_fields if field not in data]

        if missing_fields:
            raise IRValidatorException(f"Faltan los siguientes campos requeridos: {', '.join(missing_fields)}")

        return data

    except yaml.YAMLError as e:
        raise IRValidatorException(f"Error al parsear el archivo YAML: {str(e)}")
    except FileNotFoundError:
        raise IRValidatorException(f"No se encontró el archivo: {yaml_file}")
    except Exception as e:
        raise IRValidatorException(f"Error inesperado: {str(e)}")

class IRValidatorException(Exception):
    pass

def _include_groups(self, parser_dict):
    """
    Resuelve la directiva de inclusión del diccionario en los archivos de especificación.
    """
    if not parser_dict:
        return {}

    result = {}
    for key, value in parser_dict.items():
        if isinstance(value, dict):
            if '@include' in value:
                include_file = value['@include']
                try:
                    with open(include_file, 'r') as f:
                        included_content = self._parse_yaml(f)
                        result[key] = included_content
                except FileNotFoundError:
                    raise FileNotFoundError(f"Include file not found: {include_file}")
            else:
                result[key] = self._include_groups(value)
        else:
            result[key] = value

    return result

def get_spec_defaults(self):
    """
    Resolver los valores de los argumentos desde la especificación y otras fuentes.
    """
    defaults = {}

    if hasattr(self, 'spec') and self.spec:
        # Obtener valores por defecto de la especificación
        for param_name, param in self.spec.parameters.items():
            if hasattr(param, 'default'):
                defaults[param_name] = param.default

        # Obtener valores de la configuración global si existe
        if hasattr(self, 'config') and self.config:
            for key, value in self.config.items():
                if key in self.spec.parameters:
                    defaults[key] = value

        # Obtener valores de variables de entorno
        for param_name in self.spec.parameters:
            env_value = os.environ.get(param_name.upper())
            if env_value is not None:
                defaults[param_name] = env_value

    return defaults

def validate_arg_deprecation(self, cli_args, answer_file_args):
    """
    Valida y muestra los argumentos obsoletos.

    :param cli_args: el diccionario de argumentos provenientes de la línea de comandos (CLI)
    :param answer_file_args: el diccionario de argumentos provenientes de archivos
    """
    deprecated_args = {
        'force': 'use --yes instead',
        'debug': 'use --verbose instead',
        'quiet': 'use --silent instead'
    }

    # Check CLI arguments
    for arg, replacement in deprecated_args.items():
        if arg in cli_args and cli_args[arg]:
            print(f"Warning: The argument '--{arg}' is deprecated. {replacement}.")

    # Check answer file arguments 
    for arg, replacement in deprecated_args.items():
        if arg in answer_file_args and answer_file_args[arg]:
            print(f"Warning: The argument '{arg}' in the answer file is deprecated. {replacement}.")

def validar_argumentos_requeridos(self, args):
    """
    Verifica si se han proporcionado todos los argumentos requeridos.
    """
    if not args:
        return False

    for arg in args:
        if arg is None or (isinstance(arg, str) and not arg.strip()):
            return False

    return True

def _get_conditionally_required_args(self, command_name, options_spec, args):
    """
    Lista los argumentos con la condición ``required_when`` que coincide.

    :param command_name: el nombre del comando.
    :param options_spec: la lista de opciones de especificación del comando.
    :param args: los argumentos de entrada recibidos.
    :return: list, lista de nombres de argumentos que coinciden con la condición ``required_when``.
    """
    conditionally_required = []

    for option in options_spec:
        if 'required_when' in option:
            required_condition = option['required_when']

            # Evaluar la condición required_when
            if isinstance(required_condition, str):
                # Si es una cadena, evaluar como expresión
                try:
                    condition_met = eval(required_condition, {'args': args})
                except:
                    condition_met = False
            elif callable(required_condition):
                # Si es una función, llamarla con los argumentos
                try:
                    condition_met = required_condition(args)
                except:
                    condition_met = False
            else:
                condition_met = bool(required_condition)

            # Si la condición se cumple, agregar el argumento a la lista
            if condition_met:
                conditionally_required.append(option['name'])

    return conditionally_required

def validate_length_args(self, args):
    """
    Verifica si el valor de los argumentos no supera la longitud especificada.

    :param args: Los argumentos recibidos.
    """
    for arg in args:
        if isinstance(arg, str) and len(arg) > 255:
            raise ValueError(f"El argumento '{arg}' excede la longitud máxima permitida de 255 caracteres")
        elif isinstance(arg, (list, tuple, dict, set)) and len(arg) > 1000:
            raise ValueError(f"El argumento '{arg}' excede la longitud máxima permitida de 1000 elementos")

def validate_choices_args(self, args):
    """
    Verifica si el valor de los argumentos de elección es una de las opciones disponibles.  

    :param args: Los argumentos recibidos.  
    """
    for arg_name, arg_value in args.items():
        if hasattr(self, f'_{arg_name}_choices'):
            choices = getattr(self, f'_{arg_name}_choices')
            if arg_value not in choices:
                raise ValueError(f"Invalid value '{arg_value}' for argument '{arg_name}'. "
                               f"Valid choices are: {choices}")

def validate_min_max_args(self, args):
    """
    Verifica si el valor de los argumentos está entre los valores mínimo y máximo.

    :param args: Los argumentos recibidos.
    """
    for arg_name, arg_value in args.items():
        if hasattr(self, f'min_{arg_name}') and hasattr(self, f'max_{arg_name}'):
            min_val = getattr(self, f'min_{arg_name}')
            max_val = getattr(self, f'max_{arg_name}')

            if not (min_val <= arg_value <= max_val):
                raise ValueError(f'El valor de {arg_name} debe estar entre {min_val} y {max_val}')

def get_nested_custom_and_control_args(self, args):
    """
    Divide los argumentos de entrada en controlados, anidados y personalizados.

    Argumentos de control: controlan el comportamiento de IR. Estos argumentos no se incluirán en el archivo spec yml.
    Argumentos anidados: son utilizados por los playbooks de Ansible y se incluirán en el archivo spec yml.
    Argumentos personalizados: Variables personalizadas de Ansible que se usarán en lugar del uso normal de argumentos anidados.

    :param args: la lista recopilada de argumentos.
    :return: (dict, dict): diccionarios planos (control_args, nested_args)
    """
    # Initialize empty dictionaries
    control_args = {}
    nested_args = {}
    custom_args = {}

    # Iterate through all arguments
    for arg_name, arg_value in args.items():
        if arg_name.startswith('--'):
            # Control arguments start with '--'
            clean_name = arg_name[2:]  # Remove '--' prefix
            control_args[clean_name] = arg_value
        elif '__' in arg_name:
            # Nested arguments contain '__'
            parent, child = arg_name.split('__', 1)
            if parent not in nested_args:
                nested_args[parent] = {}
            nested_args[parent][child] = arg_value
        elif arg_name.startswith('custom_'):
            # Custom arguments start with 'custom_'
            clean_name = arg_name[7:]  # Remove 'custom_' prefix
            custom_args[clean_name] = arg_value
        else:
            # Regular nested arguments
            nested_args[arg_name] = arg_value

    # Merge custom args into nested args, overwriting any conflicts
    for key, value in custom_args.items():
        if key in nested_args:
            if isinstance(nested_args[key], dict):
                nested_args[key].update(value if isinstance(value, dict) else {key: value})
            else:
                nested_args[key] = value
        else:
            nested_args[key] = value

    return control_args, nested_args

def merge_extra_vars(vars_dict, extra_vars=None):
    """
    Extiende ``vars_dict`` con ``extra-vars``

    :param vars_dict: Diccionario en el que se fusionarán las extra-vars  
    :param extra_vars: Lista de extra-vars
    """
    if extra_vars is None:
        return vars_dict

    if isinstance(extra_vars, list):
        for extra_var in extra_vars:
            if isinstance(extra_var, dict):
                vars_dict.update(extra_var)
    elif isinstance(extra_vars, dict):
        vars_dict.update(extra_vars)

    return vars_dict

def ansible_playbook(ir_workspace, ir_plugin, playbook_path, verbose=None, extra_vars=None, ansible_args=None):
    """
    Envuelve la interfaz de línea de comandos (CLI) de 'ansible-playbook'.

    :param ir_workspace: Un objeto Infrared Workspace que representa el espacio de trabajo activo.
    :param ir_plugin: Un objeto InfraredPlugin del plugin actual.
    :param playbook_path: La ruta del playbook que se va a ejecutar.
    :param verbose: Nivel de verbosidad de Ansible.
    :param extra_vars: dict. Se pasa a Ansible como extra-vars.
    :param ansible_args: dict de argumentos de ansible-playbook que se pasan directamente a Ansible.
    """
    # Construir el comando base
    cmd = ['ansible-playbook', playbook_path]

    # Agregar nivel de verbosidad si está especificado
    if verbose:
        if isinstance(verbose, bool):
            cmd.append('-v')
        elif isinstance(verbose, int):
            cmd.append('-' + 'v' * verbose)

    # Agregar variables extra si existen
    if extra_vars:
        for key, value in extra_vars.items():
            cmd.extend(['--extra-vars', f'{key}={value}'])

    # Agregar inventario del workspace
    if hasattr(ir_workspace, 'inventory'):
        cmd.extend(['-i', ir_workspace.inventory])

    # Agregar argumentos adicionales de ansible si existen
    if ansible_args:
        for arg, value in ansible_args.items():
            if value is True:
                cmd.append(f'--{arg}')
            elif value is not None:
                cmd.extend([f'--{arg}', str(value)])

    # Ejecutar el comando
    import subprocess
    try:
        result = subprocess.run(cmd, check=True, text=True, capture_output=True)
        return result
    except subprocess.CalledProcessError as e:
        raise Exception(f"Error ejecutando ansible-playbook: {e.stderr}")

def _convert_non_cli_args(self, parser_name, values_dict):
    """
    Convierte los argumentos a los tipos correctos modificando el parámetro values_dict.

    Por defecto, todos los valores son cadenas de texto (strings).

    :param parser_name: El nombre del comando, por ejemplo: main, virsh, ospd, etc.
    :param values_dict: El diccionario con los argumentos.
    """
    # Obtener la configuración del parser
    parser_config = self.parsers_config.get(parser_name, {})

    # Iterar sobre los argumentos y convertirlos según su tipo
    for arg_name, value in values_dict.items():
        # Obtener la configuración del argumento específico
        arg_config = parser_config.get(arg_name, {})
        arg_type = arg_config.get('type', str)  # Por defecto es string

        # Saltar si el valor es None
        if value is None:
            continue

        try:
            # Convertir listas
            if isinstance(value, list):
                values_dict[arg_name] = [arg_type(item) for item in value]
            # Convertir valores booleanos
            elif arg_type == bool:
                if isinstance(value, str):
                    values_dict[arg_name] = value.lower() in ('true', 't', 'yes', 'y', '1')
                else:
                    values_dict[arg_name] = bool(value)
            # Convertir otros tipos
            else:
                values_dict[arg_name] = arg_type(value)

        except (ValueError, TypeError):
            # Si hay error en la conversión, mantener el valor original
            continue

def get_plugin_spec_flatten_dict(plugin_dir):
    """
    Crea un diccionario plano a partir de la especificación del plugin.

    :param plugin_dir: Una ruta al directorio del plugin  
    :return: Un diccionario plano que contiene las propiedades del plugin
    """
    flattened = {}

    def flatten_dict(d, parent_key=''):
        for key, value in d.items():
            new_key = f"{parent_key}.{key}" if parent_key else key

            if isinstance(value, dict):
                flatten_dict(value, new_key)
            else:
                flattened[new_key] = value

    try:
        # Intenta leer el archivo spec.json del directorio del plugin
        import json
        import os

        spec_path = os.path.join(plugin_dir, 'spec.json')

        if not os.path.exists(spec_path):
            return {}

        with open(spec_path, 'r') as f:
            spec = json.load(f)

        # Aplana el diccionario recursivamente
        flatten_dict(spec)

        return flattened

    except Exception as e:
        print(f"Error al procesar la especificación del plugin: {str(e)}")
        return {}
